mapper.insert:
INSERT INTO reminder (
    user_medicine_id, dosage, reminder_time,
    days_of_week, start_date, end_date, status
) VALUES (
             #{userMedicineId}, #{dosage}, #{reminderTime},
             #{daysOfWeek}, #{startDate}, #{endDate}, #{status}
         )

mapper.select:
SELECT r.*, u.openid
FROM reminder r
         INNER JOIN user_medicine um ON r.user_medicine_id = um.id
         INNER JOIN users u ON um.user_id = u.id
WHERE u.openid = #{openid}
AND r.status IN (0, 1)   
AND r.start_date <= #{todayDate}
AND r.end_date >= #{todayDate}
AND FIND_IN_SET(#{todayWeek}, r.days_of_week)
ORDER BY r.reminder_time
